sql:
SELECT note_text
FROM production_notes
WHERE note_type = 'Informational';

SELECT criteria_id, element_id, min_content, max_content, approved
FROM qc_criteria
WHERE glass_type_id = 1;

SELECT glass_type_name
FROM glass_types
WHERE glass_type_id = 1;

SELECT sample_quality 
FROM glass_samples 
WHERE sample_id = 1;

SELECT AVG(content) AS average_content
FROM sample_elements
WHERE element_id = 0;

SELECT sample_id, refractive_index
FROM glass_samples
WHERE refractive_index > (SELECT AVG(refractive_index) FROM glass_samples);

external_knowledge:
High-quality glass samples refer to samples with a 'High' rating in the 'sample_quality' field; 
Top half of samples refer to samples with a cumulative distribution of 0.5 or less within their batch when ordered by refractive index in descending order; 
Certified inspectors are those with a certification expiry date later than the current date.
